def solve(las_files):
    results = []
    for las_file in las_files:
        with open(las_file, 'r') as file:
            content = file.readlines()
            # Process the LAS file content
            header = {}
            data = []
            current_section = None

            for line in content:
                line = line.strip()
                if line.startswith('#'):
                    continue
                if line.startswith('~'):
                    current_section = line[1:]
                    continue
                if current_section is None:
                    continue
                if current_section == 'VERSION':
                    header['version'] = line
                elif current_section == 'WELL':
                    header['well'] = line
                elif current_section == 'PARAMETER':
                    key, value = line.split()
                    header[key] = value
                else:
                    data.append(line.split())

            results.append({'header': header, 'data': data})

    return results
